56	// ExecutionCleanupMetadata records the ownership metadata for one DDx temp
57	// execution directory.
58	type ExecutionCleanupMetadata struct {
59		ProjectRoot  string `json:"project_root,omitempty"`
60		BeadID       string `json:"bead_id,omitempty"`
61		AttemptID    string `json:"attempt_id,omitempty"`
62		WorktreePath string `json:"worktree_path,omitempty"`
63		Registered   bool   `json:"registered,omitempty"`
64		Preserved    bool   `json:"preserved,omitempty"`
65		// ActiveCandidateCycle is set by AttemptCycleCoordinator while it holds the
66		// worktree open for candidate evaluation (checks, review, repair). The
67		// cleanup manager preserves any worktree with this flag set so it is never
68		// deleted mid-cycle before the coordinator reaches terminal disposition.
69		ActiveCandidateCycle bool `json:"active_candidate_cycle,omitempty"`
70		// Candidate-cycle metadata lets crash recovery distinguish a stale
71		// unpinned worktree from one that still has a project-root candidate ref
