923	func (m *ExecutionCleanupManager) removeStaleRunState(state RunState, summary *ExecutionCleanupSummary) (bool, int64) {
924		path := runStatePath(m.ProjectRoot)
925		clear := func() error {
926			return ClearRunState(m.ProjectRoot)
927		}
928		if state.AttemptID != "" {
929			if attemptPath, err := runStateAttemptPath(m.ProjectRoot, state.AttemptID); err == nil {
930				path = attemptPath
931				clear = func() error {
