955					Path:    path,
956					Class:   "run_state_clear",
957					Message: err.Error(),
958				})
959			}
960		}
961		if !present {
962			return false, 0
963		}
964		class := "removed_run_state"
965		if m.DryRun {
966			class = "would_remove_run_state"
967		}
968		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
969			Path:    path,
970			Class:   class,
971			Message: "stale run-state",
972			Bytes:   bytes,
973			Inodes:  1,
974		})
975		return true, bytes
976	}
