1100	func measureTreeWithContext(ctx context.Context, path string) (bytes int64, inodes int64, err error) {
1101		if ctx != nil {
1102			if err := ctx.Err(); err != nil {
1103				return 0, 0, err
1104			}
1105		}
1106		info, err := os.Lstat(path)
1107		if err != nil {
1108			return 0, 0, err
1109		}
1110		if !info.IsDir() {
1111			return info.Size(), 1, nil
1112		}
1113		err = filepath.WalkDir(path, func(p string, d os.DirEntry, walkErr error) error {
1114			if ctx != nil {
1115				if err := ctx.Err(); err != nil {
1116					return err
1117				}
1118			}
1119			if walkErr != nil {
1120				return walkErr
1121			}
1122			inodes++
1123			fi, statErr := d.Info()
1124			if statErr != nil {
1125				return statErr
1126			}
1127			bytes += fi.Size()
1128			return nil
1129		})
1130		return bytes, inodes, err
1131	}
