1342	// workerDirPID reads the PID from .ddx/workers/<id>/status.json. Returns 0
1343	// if the file cannot be read or has no PID.
1344	func workerDirPID(dirPath string) int {
1345		data, err := os.ReadFile(filepath.Join(dirPath, "status.json"))
1346		if err != nil {
1347			return 0
1348		}
1349		var rec struct {
1350			PID int `json:"pid"`
1351		}
1352		if err := json.Unmarshal(data, &rec); err != nil {
1353			return 0
1354		}
1355		return rec.PID
1356	}
