1366	// pruneWorkerDirs deletes .ddx/workers/<id>/ directories whose mtime is older
1367	// than m.RetainDays. Directories whose status.json PID is still alive are
1368	// skipped. No-op when RetainDays == 0.
1369	func (m *ExecutionCleanupManager) pruneWorkerDirs(ctx context.Context, summary *ExecutionCleanupSummary, now time.Time) {
1370		if m.RetainDays == 0 {
1371			return
1372		}
1373		if ctx != nil && ctx.Err() != nil {
1374			return
1375		}
1376		cutoff := now.AddDate(0, 0, -m.RetainDays)
1377	
1378		root := workerDirsRoot(m.ProjectRoot)
1379		entries, err := os.ReadDir(root)
1380		if err != nil {
1381			if !errors.Is(err, os.ErrNotExist) {
1382				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1383					Path:    root,
1384					Class:   "worker_dir_read",
1385					Message: err.Error(),
1386				})
1387			}
1388			return
1389		}
1390	
1391		for _, entry := range entries {
1392			if ctx != nil && ctx.Err() != nil {
1393				return
1394			}
1395			if !entry.IsDir() {
1396				continue
1397			}
1398			dirPath := filepath.Join(root, entry.Name())
1399			relPath := filepath.ToSlash(filepath.Join(".ddx/workers", entry.Name()))
1400	
1401			if pid := workerDirPID(dirPath); pid > 0 && trackerProcessAlive(pid) {
1402				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1403					Path:    relPath,
1404					Class:   "preserved_active_worker_dir",
1405					Message: fmt.Sprintf("worker pid %d is alive", pid),
1406				})
1407				continue
1408			}
1409	
1410			info, infoErr := entry.Info()
1411			if infoErr != nil {
1412				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1413					Path:    dirPath,
1414					Class:   "worker_dir_stat",
1415					Message: infoErr.Error(),
1416				})
1417				continue
1418			}
1419			if !info.ModTime().Before(cutoff) {
1420				continue
1421			}
1422	
1423			if !m.DryRun {
1424				if err := os.RemoveAll(dirPath); err != nil {
1425					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1426						Path:    dirPath,
1427						Class:   "worker_dir_remove",
1428						Message: err.Error(),
1429					})
1430					continue
1431				}
1432			}
1433			summary.RemovedWorkerDirs++
1434			class := "removed_worker_dir"
1435			if m.DryRun {
1436				class = "would_remove_worker_dir"
1437			}
1438			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1439				Path:    relPath,
1440				Class:   class,
1441				Message: fmt.Sprintf("worker dir older than %d days", m.RetainDays),
1442			})
1443		}
1444	}
