24	func (r *cleanupProcessRunner) Run(opts RunArgs) (*Result, error) {
25		cmd := exec.Command("sh", "-c", "cd \"$1\" && sh -c 'sleep 60' & wait", "sh", opts.WorkDir)
26		cmd.Env = append(os.Environ(), DDXModeEnvKey+"="+DDXModeBeadExecution)
27		if err := cmd.Start(); err != nil {
28			return &Result{ExitCode: 1, Error: err.Error()}, nil
