30		go func() { _, _ = cmd.Process.Wait() }()
31		r.started <- cmd.Process.Pid
32		ctx := opts.Context
33		if ctx == nil {
34			ctx = context.Background()
35		}
36		<-ctx.Done()
37		return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
38	}
