48	func inspectOrphanHarnessProcess(pid int) (orphanHarnessProcess, bool) {
49		base := filepath.Join("/proc", strconv.Itoa(pid))
50		cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
51		if err != nil {
52			return orphanHarnessProcess{}, false
53		}
54		cmdline := decodeOrphanHarnessCmdline(cmdlineRaw)
55		if cmdline == "" {
56			return orphanHarnessProcess{}, false
57		}
58		cwd, _ := os.Readlink(filepath.Join(base, "cwd"))
59		ppid, ok := readOrphanHarnessParentPID(filepath.Join(base, "stat"))
60		if !ok {
61			return orphanHarnessProcess{}, false
62		}
63		return orphanHarnessProcess{
64			PID:     pid,
65			PPID:    ppid,
66			Command: cmdline,
67			Cwd:     cwd,
68		}, true
69	}
70	
71	func decodeOrphanHarnessCmdline(raw []byte) string {
72		if len(raw) == 0 {
73			return ""
74		}
75		if raw[len(raw)-1] == 0 {
76			raw = raw[:len(raw)-1]
77		}
78		parts := bytes.Split(raw, []byte{0})
79		out := make([]string, 0, len(parts))
80		for _, p := range parts {
81			if len(p) == 0 {
82				continue
83			}
84			out = append(out, string(p))
85		}
86		return strings.Join(out, " ")
87	}
88	
89	func readOrphanHarnessParentPID(statPath string) (int, bool) {
90		data, err := os.ReadFile(statPath)
91		if err != nil {
92			return 0, false
93		}
94		close := strings.LastIndex(string(data), ")")
95		if close < 0 {
96			return 0, false
97		}
98		tail := strings.Fields(string(data[close+1:]))
99		if len(tail) < 2 {
100			return 0, false
101		}
102		ppid, err := strconv.Atoi(tail[1])
103		if err != nil {
104			return 0, false
105		}
106		return ppid, true
107	}
108	
109	func killProcessGroup(pid int) error {
110		if pid <= 0 {
111			return nil
112		}
113		return syscall.Kill(-pid, syscall.SIGKILL)
114	}
