117	func attemptCleanupCandidates(processes []attemptProcessInfo, baseline map[int]struct{}, worktree string) []attemptProcessInfo {
118		self := os.Getpid()
119		out := make([]attemptProcessInfo, 0)
120		for _, proc := range processes {
121			if proc.PID <= 0 || proc.PID == self {
122				continue
123			}
124			if baseline != nil {
125				if _, seen := baseline[proc.PID]; seen {
126					continue
127				}
128			}
129			if processCwdWithin(proc.Cwd, worktree) || processCommandMentionsAttempt(proc.Command, worktree) {
130				out = append(out, proc)
131			}
132		}
133		sort.Slice(out, func(i, j int) bool {
134			di := processDepth(processes, out[i].PID)
135			dj := processDepth(processes, out[j].PID)
136			if di == dj {
137				return out[i].PID > out[j].PID
138			}
139			return di > dj
140		})
141		return out
142	}
143	
144	func processDepth(processes []attemptProcessInfo, pid int) int {
145		parent := map[int]int{}
146		for _, proc := range processes {
147			parent[proc.PID] = proc.PPID
148		}
149		depth := 0
150		for pid > 0 {
151			ppid := parent[pid]
152			if ppid <= 0 || ppid == pid {
153				return depth
154			}
155			depth++
156			pid = ppid
157		}
158		return depth
159	}
