177	func canonicalCleanupPath(path string) string {
178		abs, err := filepath.Abs(path)
179		if err != nil {
180			abs = filepath.Clean(path)
181		}
182		if real, err := filepath.EvalSymlinks(abs); err == nil {
183			abs = real
184		}
185		return filepath.Clean(abs)
186	}
