188	func killAttemptProcesses(candidates []attemptProcessInfo, report *attemptProcessCleanupReport) {
189		for _, proc := range candidates {
190			if proc.PID <= 0 || proc.PID == os.Getpid() {
191				continue
192			}
193			if err := syscall.Kill(proc.PID, syscall.SIGTERM); err != nil && err != syscall.ESRCH {
194				report.KillErrors = append(report.KillErrors, fmt.Sprintf("SIGTERM pid %d: %v", proc.PID, err))
195			}
196		}
197		deadline := time.Now().Add(750 * time.Millisecond)
198		for time.Now().Before(deadline) {
199			allGone := true
200			for _, proc := range candidates {
201				if signalProcessAlive(proc.PID) {
202					allGone = false
203					break
204				}
205			}
206			if allGone {
207				return
208			}
209			time.Sleep(25 * time.Millisecond)
210		}
211		for _, proc := range candidates {
212			if !signalProcessAlive(proc.PID) {
213				continue
214			}
215			if err := syscall.Kill(proc.PID, syscall.SIGKILL); err != nil && err != syscall.ESRCH {
216				report.KillErrors = append(report.KillErrors, fmt.Sprintf("SIGKILL pid %d: %v", proc.PID, err))
217			}
218		}
219	}
