228	func scanAttemptProcesses(ctx context.Context) ([]attemptProcessInfo, error) {
229		cmd := exec.CommandContext(ctx, "ps", "-axo", "pid=,ppid=,pgid=,command=")
230		out, err := cmd.Output()
231		if err != nil {
232			return nil, err
233		}
234		processes := parseAttemptPS(out)
235		for i := range processes {
236			processes[i].Cwd = readProcessCwd(processes[i].PID)
237		}
238		return processes, nil
239	}
240	
241	func parseAttemptPS(out []byte) []attemptProcessInfo {
242		lines := bytes.Split(out, []byte{'\n'})
243		processes := make([]attemptProcessInfo, 0, len(lines))
244		for _, line := range lines {
245			fields := strings.Fields(string(line))
246			if len(fields) < 3 {
247				continue
248			}
249			pid, pidErr := strconv.Atoi(fields[0])
250			ppid, ppidErr := strconv.Atoi(fields[1])
251			pgid, pgidErr := strconv.Atoi(fields[2])
252			if pidErr != nil || ppidErr != nil || pgidErr != nil {
253				continue
254			}
255			cmdline := ""
256			if len(fields) > 3 {
257				cmdline = strings.Join(fields[3:], " ")
258			}
259			processes = append(processes, attemptProcessInfo{
260				PID:     pid,
261				PPID:    ppid,
262				PGID:    pgid,
263				Command: cmdline,
264			})
265		}
266		return processes
267	}
268	
269	func readProcessCwd(pid int) string {
270		if pid <= 0 {
271			return ""
272		}
273		if cwd, err := os.Readlink(filepath.Join("/proc", strconv.Itoa(pid), "cwd")); err == nil {
274			return cwd
275		}
276		return ""
277	}
