// scanStaleAttemptProcesses scans for processes whose cwd is under the
// execution temp root and that are not in a live worktree. In dry-run mode,
// findings are recorded with WouldKill=true but the killer is not invoked.
func (m *ExecutionCleanupManager) scanStaleAttemptProcesses(ctx context.Context, summary *ExecutionCleanupSummary, liveWorktrees map[string]struct{}) {
	scanner := m.ProcessScanner
	if scanner == nil {
		scanner = newDefaultStaleAttemptProcessScanner()
	}
	execRoot := m.tempRoot()
	if execRoot == "" {
		return
	}
	findings, unavailable, err := scanner.ScanAttemptDescendants(ctx, execRoot)
	if unavailable {
		summary.ProcessCleanupUnavailable = true
		return
	}
	if err != nil {
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Class:   "process_scan",
			Message: err.Error(),
		})
		return
	}
	for _, f := range findings {
		if isProcessInLiveWorktree(f, liveWorktrees) {
			continue
		}
		f.WouldKill = true
		if !m.DryRun && m.ProcessKiller != nil {
			if killErr := m.ProcessKiller(f.PID); killErr != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Class:   "process_kill",
					Message: fmt.Sprintf("kill pid %d: %v", f.PID, killErr),
				})
			}
		}
		summary.StaleAttemptProcesses = append(summary.StaleAttemptProcesses, f)
		summary.StaleAttemptProcessCount++
	}
}

func isProcessInLiveWorktree(f ExecutionCleanupProcessFinding, liveWorktrees map[string]struct{}) bool {
	if f.Worktree != "" {
		if _, live := liveWorktrees[filepath.Clean(f.Worktree)]; live {
			return true
		}
	}
	if f.Cwd != "" {
		cwdClean := filepath.Clean(f.Cwd)
		for liveWt := range liveWorktrees {
			if cwdClean == liveWt || strings.HasPrefix(cwdClean, liveWt+string(filepath.Separator)) {
				return true
			}
		}
	}
	return false
}

