//go:build linux

package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
)

type procStaleAttemptDescendantScanner struct{}

func newDefaultStaleAttemptProcessScanner() staleAttemptProcessScanner {
	return procStaleAttemptDescendantScanner{}
}

// ScanAttemptDescendants reads /proc and returns all processes whose cwd is
// under execRoot. Detection is by ownership evidence (cwd path), not command
// name, so non-harness commands (sh, cargo, test servers) are included.
func (procStaleAttemptDescendantScanner) ScanAttemptDescendants(ctx context.Context, execRoot string) ([]ExecutionCleanupProcessFinding, bool, error) {
	if execRoot == "" {
		return nil, false, nil
	}
	cleanRoot := canonicalCleanupPath(execRoot)
	rootPrefix := cleanRoot + string(filepath.Separator)

	entries, err := os.ReadDir("/proc")
	if err != nil {
		return nil, false, fmt.Errorf("scan attempt descendants: read /proc: %w", err)
	}

	self := os.Getpid()
	var findings []ExecutionCleanupProcessFinding

	for _, entry := range entries {
		if ctx != nil && ctx.Err() != nil {
			return findings, false, ctx.Err()
		}
		if !entry.IsDir() {
			continue
		}
		pid, err := strconv.Atoi(entry.Name())
		if err != nil || pid <= 0 || pid == self {
			continue
		}

		base := filepath.Join("/proc", entry.Name())
		cwd, err := os.Readlink(filepath.Join(base, "cwd"))
		if err != nil {
			continue
		}

		cleanCwd := canonicalCleanupPath(cwd)
		if cleanCwd != cleanRoot && !strings.HasPrefix(cleanCwd, rootPrefix) {
			continue
		}

		worktree := attemptWorktreeFromCwd(cleanCwd, cleanRoot)
		cmdline := readAttemptDescendantCmdline(base)
		ppid, _ := readOrphanHarnessParentPID(filepath.Join(base, "stat"))
		pgid := readAttemptDescendantPGID(filepath.Join(base, "stat"))

		findings = append(findings, ExecutionCleanupProcessFinding{
			PID:         pid,
			PPID:        ppid,
			PGID:        pgid,
			Command:     cmdline,
			Cwd:         cwd,
			Worktree:    worktree,
			StaleReason: "cwd within DDx execution root",
		})
	}

	return findings, false, nil
}

// attemptWorktreeFromCwd extracts the attempt worktree path from a process cwd
// that lies under execRoot by taking the first path component after execRoot.
func attemptWorktreeFromCwd(cleanCwd, cleanRoot string) string {
	rel, err := filepath.Rel(cleanRoot, cleanCwd)
	if err != nil || rel == "." || strings.HasPrefix(rel, "..") {
		return cleanRoot
	}
	parts := strings.SplitN(filepath.ToSlash(rel), "/", 2)
	if len(parts) == 0 || parts[0] == "" {
		return cleanRoot
	}
	return filepath.Join(cleanRoot, filepath.FromSlash(parts[0]))
}

func readAttemptDescendantCmdline(procBase string) string {
	data, err := os.ReadFile(filepath.Join(procBase, "cmdline"))
	if err != nil || len(data) == 0 {
		return ""
	}
	s := decodeOrphanHarnessCmdline(data)
	if len(s) > 256 {
		s = s[:256]
	}
	return s
}

// readAttemptDescendantPGID extracts the process group ID from /proc/PID/stat.
func readAttemptDescendantPGID(statPath string) int {
	data, err := os.ReadFile(statPath)
	if err != nil {
		return 0
	}
	closeIdx := strings.LastIndex(string(data), ")")
	if closeIdx < 0 {
		return 0
	}
	// /proc/PID/stat after ")": state ppid pgrp session ...
	tail := strings.Fields(string(data[closeIdx+1:]))
	if len(tail) < 3 {
		return 0
	}
	pgid, err := strconv.Atoi(tail[2])
	if err != nil {
		return 0
	}
	return pgid
}

