func TestExecutionCleanupManager_DryRunReportsStaleAttemptDescendantProcesses(t *testing.T) {
	projectRoot := t.TempDir()
	tempRoot := t.TempDir()

	// Create a stale attempt worktree dir under tempRoot.
	attemptDir := filepath.Join(tempRoot, ExecuteBeadWtPrefix+"ddx-testattempt")
	require.NoError(t, os.MkdirAll(attemptDir, 0o755))
	require.NoError(t, WriteExecutionCleanupMetadata(attemptDir, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		WorktreePath: attemptDir,
	}))

	killerCalled := false

	scanner := &stubStaleAttemptProcessScanner{
		findings: []ExecutionCleanupProcessFinding{
			{
				PID:         99991,
				PPID:        1,
				Command:     "sh -c sleep 60",
				Cwd:         attemptDir,
				Worktree:    attemptDir,
				StaleReason: "cwd within DDx execution root",
			},
		},
	}

	mgr := &ExecutionCleanupManager{
		ProjectRoot:    projectRoot,
		TempRoot:       tempRoot,
		DryRun:         true,
		Now:            func() time.Time { return time.Now() },
		Probe:          executionCleanupTestProbe{},
		ProcessScanner: scanner,
		ProcessKiller:  func(pid int) error { killerCalled = true; return nil },
	}

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.False(t, summary.ProcessCleanupUnavailable, "process cleanup should be available with stub scanner")
	assert.Equal(t, 1, summary.StaleAttemptProcessCount)
	require.Len(t, summary.StaleAttemptProcesses, 1)

	f := summary.StaleAttemptProcesses[0]
	assert.Equal(t, 99991, f.PID)
	assert.NotEmpty(t, f.Command, "finding must report command")
	assert.NotEmpty(t, f.Worktree, "finding must report worktree")
	assert.NotEmpty(t, f.StaleReason, "finding must report stale reason")
	assert.True(t, f.WouldKill, "dry-run finding must have would_kill=true")

	assert.False(t, killerCalled, "killer must not be called during dry-run")
}

func TestExecutionCleanupManager_DetectsNonHarnessDescendantByOwnershipEvidence(t *testing.T) {
	projectRoot := t.TempDir()
	tempRoot := t.TempDir()

	attemptDir := filepath.Join(tempRoot, ExecuteBeadWtPrefix+"ddx-nonharness")
	require.NoError(t, os.MkdirAll(attemptDir, 0o755))
	require.NoError(t, WriteExecutionCleanupMetadata(attemptDir, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		WorktreePath: attemptDir,
	}))

	// Non-harness commands detected by cwd ownership evidence, not command matching.
	nonHarnessCommands := []string{"sh", "cargo test", "./test-server --port 8080"}
	var findings []ExecutionCleanupProcessFinding
	for i, cmd := range nonHarnessCommands {
		findings = append(findings, ExecutionCleanupProcessFinding{
			PID:         20000 + i,
			Command:     cmd,
			Cwd:         attemptDir,
			Worktree:    attemptDir,
			StaleReason: "cwd within DDx execution root",
		})
	}

	scanner := &stubStaleAttemptProcessScanner{findings: findings}
	mgr := &ExecutionCleanupManager{
		ProjectRoot:    projectRoot,
		TempRoot:       tempRoot,
		DryRun:         true,
		Now:            func() time.Time { return time.Now() },
		Probe:          executionCleanupTestProbe{},
		ProcessScanner: scanner,
	}

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.Equal(t, len(nonHarnessCommands), summary.StaleAttemptProcessCount)
	require.Len(t, summary.StaleAttemptProcesses, len(nonHarnessCommands))

	detected := make(map[string]bool)
	for _, f := range summary.StaleAttemptProcesses {
		detected[f.Command] = true
