func TestExecutionCleanupManager_UnsupportedPlatformReportsProcessCleanupUnavailable(t *testing.T) {
	projectRoot := t.TempDir()
	tempRoot := t.TempDir()

	mgr := &ExecutionCleanupManager{
		ProjectRoot:    projectRoot,
		TempRoot:       tempRoot,
		DryRun:         true,
		Now:            func() time.Time { return time.Now() },
		ProcessScanner: stubUnavailableStaleAttemptProcessScanner{},
	}

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.True(t, summary.ProcessCleanupUnavailable, "unsupported platform must set ProcessCleanupUnavailable=true")
	assert.Empty(t, summary.StaleAttemptProcesses)
	assert.Zero(t, summary.StaleAttemptProcessCount)
}

