57		for _, path := range want {
58			wantSet[path] = true
59		}
60		var overlap []string
61		for _, path := range current {
62			if wantSet[path] {
63				overlap = append(overlap, path)
64			}
65		}
66		sort.Strings(overlap)
67		return overlap
