179	func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
180		workTreeOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").CombinedOutput()
181		if err != nil {
182			return false, nil
183		}
184		if strings.TrimSpace(string(workTreeOut)) != "true" {
185			return false, fmt.Errorf("verifying project worktree for pre-dispatch checkpoint: git rev-parse --is-inside-work-tree returned %q", strings.TrimSpace(string(workTreeOut)))
186		}
187		headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput()
188		if err != nil {
189			return false, nil
190		}
191		head := strings.TrimSpace(string(headOut))
192		if head == "" {
193			return false, nil
194		}
195	
196		skipWorktreePaths, err := checkpointSkipWorktreePaths(projectRoot)
197		if err != nil {
198			return false, err
199		}
200	
201		dirtyPaths, err := preDispatchDirtyPathLister(projectRoot)
202		if err != nil {
203			return false, err
204		}
205		if len(dirtyPaths) == 0 {
206			return false, nil
207		}
208	
209		allowedPaths, blockedPaths := classifyPreDispatchDirtyPaths(dirtyPaths)
210		if len(blockedPaths) > 0 {
211			stableBlockedPaths, currentDirtyPaths, err := stablePreDispatchImplementationDirtyPaths(projectRoot, blockedPaths)
212			if err != nil {
213				return false, err
214			}
215			if len(stableBlockedPaths) > 0 {
216				return false, fmt.Errorf(
217					"%s%s; commit or clean those files before rerunning so the bead's [ddx-<id>] substantive commit stays intentional",
218					preDispatchCheckpointDirtyRefusalPrefix,
219					strings.Join(stableBlockedPaths, ", "),
220				)
221			}
222			allowedPaths, _ = classifyPreDispatchDirtyPaths(currentDirtyPaths)
223		}
224		if len(allowedPaths) == 0 {
225			return false, nil
226		}
227	
228		indexFile, err := config.CreateExecutionScratch(projectRoot, "ddx-pre-dispatch-index-*")
229		if err != nil {
230			return false, fmt.Errorf("creating temp checkpoint index: %w", err)
231		}
232		indexPath := indexFile.Name()
233		_ = indexFile.Close()
234		_ = os.Remove(indexPath)
235		defer func() { _ = os.Remove(indexPath) }()
236	
237		gitWithIndex := func(args ...string) ([]byte, error) {
238			cmd := internalgit.Command(context.Background(), projectRoot, args...)
239			cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
240			return cmd.CombinedOutput()
241		}
242	
243		if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
244			return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
245		}
246	
247		addArgs := []string{"add", "-A", "--force", "--"}
248		addArgs = append(addArgs, allowedPaths...)
249		if out, err := gitWithIndex(addArgs...); err != nil {
250			return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
251		}
252	
253		changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
254		if err != nil {
255			return false, fmt.Errorf("checking checkpoint diff: %w", err)
256		}
257		if len(bytes.TrimSpace(changedOut)) == 0 {
258			return false, nil
259		}
260	
261		treeOut, err := gitWithIndex("write-tree")
262		if err != nil {
263			return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
264		}
265		tree := strings.TrimSpace(string(treeOut))
266		msg := "chore: checkpoint pre-execute-bead " + attemptID
267		commitOut, err := internalgit.Command(context.Background(), projectRoot,
268			"-c", "user.name=ddx-checkpoint",
269			"-c", "user.email=checkpoint@ddx.local",
270			"commit-tree", tree, "-p", head, "-m", msg,
271		).CombinedOutput()
272		if err != nil {
273			return false, fmt.Errorf("creating checkpoint commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
274		}
275		commit := strings.TrimSpace(string(commitOut))
276	
277		refOut, _ := internalgit.Command(context.Background(), projectRoot, "symbolic-ref", "-q", "HEAD").Output()
278		ref := strings.TrimSpace(string(refOut))
279		if ref == "" {
280			ref = "HEAD"
281		}
282		if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", ref, commit, head).CombinedOutput(); err != nil {
283			return false, fmt.Errorf("advancing checkpoint ref: %s: %w", strings.TrimSpace(string(out)), err)
284		}
285		if out, err := internalgit.Command(context.Background(), projectRoot, "read-tree", "HEAD").CombinedOutput(); err != nil {
286			return false, fmt.Errorf("syncing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
287		}
288		if err := restoreCheckpointSkipWorktreePaths(projectRoot, skipWorktreePaths); err != nil {
289			return false, err
290		}
291		return true, nil
292	}
