294	func checkpointSkipWorktreePaths(projectRoot string) ([]string, error) {
295		out, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "-t", "-z").CombinedOutput()
296		if err != nil {
297			return nil, fmt.Errorf("listing skip-worktree paths: %s: %w", strings.TrimSpace(string(out)), err)
298		}
299		var paths []string
300		for len(out) > 0 {
301			recordEnd := bytes.IndexByte(out, 0)
302			if recordEnd == -1 {
303				recordEnd = len(out)
304			}
305			record := out[:recordEnd]
306			if recordEnd < len(out) {
307				out = out[recordEnd+1:]
308			} else {
309				out = nil
310			}
311			if len(record) < 3 || record[0] != 'S' || record[1] != ' ' {
312				continue
313			}
314			path := filepath.ToSlash(string(record[2:]))
315			if path != "" {
316				paths = append(paths, path)
317			}
318		}
319		return paths, nil
320	}
321	
322	func restoreCheckpointSkipWorktreePaths(projectRoot string, paths []string) error {
323		for start := 0; start < len(paths); start += 100 {
324			end := start + 100
325			if end > len(paths) {
326				end = len(paths)
327			}
328			args := append([]string{"update-index", "--skip-worktree", "--"}, paths[start:end]...)
329			if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
330				return fmt.Errorf("restoring skip-worktree paths after checkpoint index sync: %s: %w", strings.TrimSpace(string(out)), err)
331			}
332		}
333		return nil
334	}
335	
336	// isMaterializedSkillSymlink reports whether a path is a skill directory symlink
337	// that has been materialized into a real directory by an external tool. Skill
338	// symlinks (.crush/skills/*, .claude/skills/*, .agents/skills/*) tracked in git
339	// as symlinks (mode 120000) but present in the working tree as directories are
340	// benign and do not indicate uncommitted implementation changes.
341	func isMaterializedSkillSymlink(projectRoot, path string) bool {
342		// Check if path is in a skill directory root
343		skillDirs := []string{".crush/skills", ".claude/skills", ".agents/skills"}
344		var isSkillPath bool
345		for _, skillDir := range skillDirs {
346			if path == skillDir || strings.HasPrefix(path, skillDir+"/") {
347				isSkillPath = true
348				break
349			}
350		}
351		if !isSkillPath {
352			return false
353		}
354	
355		// Check if it's tracked in git as a symlink
356		mode, err := internalgit.Command(context.Background(), projectRoot,
357			"ls-files", "--stage", "--", path).Output()
358		if err != nil || len(mode) == 0 {
359			return false
360		}
361		// ls-files --stage output is: "<mode> <object> <stage>\t<file>"
362		// We need to extract the mode field (first field, 120000 for symlink)
363		parts := strings.Fields(string(mode))
364		if len(parts) < 1 {
365			return false
366		}
367		gitMode := parts[0]
368		if gitMode != "120000" {
369			return false
370		}
371	
372		// Check if the working tree has it as a directory
373		fullPath := filepath.Join(projectRoot, filepath.FromSlash(path))
374		info, err := os.Stat(fullPath)
375		if err != nil {
376			return false
377		}
378		return info.IsDir()
379	}
380	
381	func preDispatchCheckpointDirtyPaths(projectRoot string) ([]string, error) {
382		out, err := internalgit.Command(context.Background(), projectRoot,
383			"status", "--porcelain=v1", "-z", "--untracked-files=all", "--ignored=matching", "--", ".").CombinedOutput()
384		if err != nil {
385			return nil, fmt.Errorf("listing checkpoint dirt: %s: %w", strings.TrimSpace(string(out)), err)
386		}
387		if len(out) == 0 {
388			return nil, nil
389		}
390	
391		seen := make(map[string]bool)
392		paths := make([]string, 0, 8)
393		for len(out) > 0 {
394			recordEnd := bytes.IndexByte(out, 0)
395			if recordEnd == -1 {
396				recordEnd = len(out)
397			}
398			record := out[:recordEnd]
399			if recordEnd < len(out) {
400				out = out[recordEnd+1:]
401			} else {
402				out = nil
403			}
404			if len(record) < 3 {
405				continue
406			}
407			status := string(record[:2])
408			path := filepath.ToSlash(string(record[3:]))
409			if status == "!!" && !preDispatchCheckpointAllowedPath(path) {
410				continue
411			}
412			if preDispatchCheckpointIgnoredPath(path) {
413				continue
414			}
415			if isMaterializedSkillSymlink(projectRoot, path) {
416				continue
417			}
418			if path != "" && !seen[path] {
419				seen[path] = true
420				paths = append(paths, path)
421			}
422			if record[0] == 'R' || record[0] == 'C' {
423				recordEnd = bytes.IndexByte(out, 0)
424				if recordEnd == -1 {
425					recordEnd = len(out)
426				}
427				record = out[:recordEnd]
428				if recordEnd < len(out) {
429					out = out[recordEnd+1:]
430				} else {
431					out = nil
432				}
433				path := filepath.ToSlash(string(record))
434				if status == "!!" && !preDispatchCheckpointAllowedPath(path) {
435					continue
436				}
437				if preDispatchCheckpointIgnoredPath(path) {
438					continue
439				}
440				if isMaterializedSkillSymlink(projectRoot, path) {
441					continue
442				}
443				if path != "" && !seen[path] {
444					seen[path] = true
445					paths = append(paths, path)
446				}
447			}
448		}
449		return paths, nil
450	}
451	
452	func preDispatchCheckpointAllowedPath(path string) bool {
453		switch {
454		case path == ".ddx/beads.jsonl":
455			return true
456		case path == ".ddx/beads-archive.jsonl":
457			return true
458		case strings.HasPrefix(path, ".ddx/executions/"):
459			return true
460		case strings.HasPrefix(path, ".ddx/metrics/"):
461			return true
